// Extraire les informations du fichier détecté
const filePath = $input.item.json.path || '';
const fileName = filePath.split('/').pop() || '';
const bookId   = fileName.replace('.txt', '');

// Détecter la source depuis le chemin
const source = filePath.includes('/gallica/')    ? 'gallica'
             : filePath.includes('/gutenberg/')  ? 'gutenberg'
             : filePath.includes('/wikisource/') ? 'wikisource'
             : 'inconnu';

// Ignorer les fichiers déjà traités (_clean, _corrected)
const isAlreadyProcessed = fileName.includes('_clean') ||
                           fileName.includes('_corrected') ||
                           fileName.includes('_l3');

// Chemin du fichier VU depuis l'intérieur du conteneur Docker
// Le volume est monté : /home/pi/lexicotrend/data → /app/data
const containerPath = filePath.replace('/home/pi/lexicotrend/data', '/app/data');

return [{
  json: {
    filePath,
    containerPath,
    fileName,
    bookId,
    source,
    isAlreadyProcessed,
    detectedAt: new Date().toISOString()
  }
}];

// Fichier déjà traité — ignorer silencieusement
const fileName = $json.fileName || 'inconnu';
console.log(`Fichier ignoré (déjà traité) : ${fileName}`);
return [];

// Log erreur nettoyage
const stderr  = $('Nettoyage regex (couche 1)').item.json.stderr || '';
const bookId  = $('Extraire infos fichier').item.json.bookId || 'inconnu';
console.error(`Erreur nettoyage ${bookId} : ${stderr.substring(0,300)}`);
return [{ json: { error: 'clean_failed', bookId, stderr: stderr.substring(0,300) } }];

// Vérifier si ce nouveau livre est un outlier
// et déclencher l'enrichissement Claude si besoin
const bookId = $('Extraire infos fichier').item.json.bookId;
const metricsOut = $('Calcul métriques').item.json.stdout || '';

// L'analyse complète sera relancée par le workflow_collecte hebdo
// Ici on déclenche juste un check rapide sur ce livre
return [{
  json: {
    bookId,
    metricsOutput: metricsOut.substring(0, 200),
    nextStep: 'analysis_will_run_on_weekly_schedule',
    processedAt: new Date().toISOString()
  }
}];

const bookId      = $('Extraire infos fichier').item.json.bookId;
const source      = $('Extraire infos fichier').item.json.source;
const detectedAt  = $('Extraire infos fichier').item.json.detectedAt;
const completedAt = new Date().toISOString();

// Calcul durée de traitement
const durationMs = new Date(completedAt) - new Date(detectedAt);
const durationSec = Math.round(durationMs / 1000);

console.log(`✓ Pipeline trigger terminée pour ${bookId} en ${durationSec}s`);

return [{
  json: {
    status:      'success',
    bookId,
    source,
    detectedAt,
    completedAt,
    durationSec,
    message: `Livre ${bookId} traité avec succès en ${durationSec}s`
  }
}];
